<template>
  <div class="health-card" >
    <p :style="{color: 'var('+bmiColor+')'}">{{bmi.toFixed(2)}}</p>
    <p :style="{color: 'var('+bmiColor+')',fontSize: 1+'rem'}">{{bmitake}}</p>
  </div>
</template>

<script>
import { ref, onMounted } from 'vue';

export default {
  name: 'HealthCard',
  setup(){
    const weights = ref([])
    const weight = ref(0)
    const height = ref(1.74)
    const bmi = ref(0)
    const bmiColor = ref(null)
    const bmitake = ref("")

    onMounted(() => {
      if(localStorage.getItem('myweights')){
        weights.value = (localStorage.getItem('myweights')).split(",")
      }
      weight.value = weights.value.slice(-1)[0]
      bmi.value = weight.value/height.value/height.value
      setBmiColor(bmi.value)
    });

    function setWeight(w){
      weight.value = w
      weights.value.push(w)
      localStorage.setItem('myweights', weights.value)
    }

    function setBmiColor(bmi = bmi.value){
      if(bmi < 18.5){
        // 体重过低
        bmiColor.value = '--warningI-clr'
        bmitake.value = "体重过低"
      }else if(bmi < 24){
        //nomal
        bmiColor.value = '--nomal-clr'
        bmitake.value = "正常"
      }else if(bmi < 28){
        //pre fat
        bmiColor.value = '--warningI-clr'
        bmitake.value = "肥胖前期"
      }else if(bmi < 30){
        //fat I
        bmiColor.value = '--warningII-clr'
        bmitake.value = "I 度肥胖"
      }else if(bmi < 40){
        //fat II
        bmiColor.value = '--dangerI-clr'
        bmitake.value = "II 度肥胖"
      }else{
        //fat III
        bmiColor.value = '--dangerII-clr'
        bmitake.value = "III 度肥胖"
      }
    }

    return{
      weight,
      height,
      bmi,
      bmiColor,
      bmitake
    }
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
  .health-card {
    display: flex;
    flex-direction: column;
    align-items: center;

  }

  p {
    font-size: 2rem;
    margin: 0;
  }

</style>

