<template>
  <div class="container">
    <div class="game">
      <div class="game-title">叠乌龟</div>
      <div class="turtles">
        <div class="turtle-list">
          <div class="turtle-item">5</div>
          <div class="turtle-item">4</div>
          <div class="turtle-item">3</div>
          <div class="turtle-item">2</div>
          <div class="turtle-item">1</div>
        </div>
        <div class="turtle-game">
          <div :class="{'turtle': true, 'new5':turtle==8}" style="z-index: 10;" v-show="turtle >= 8">
            <img src="@/assets/game-img/turtle/turtle.png" style="width:200px;" />
          </div>
          <div :class="{'turtle': true, 'new4':turtle==6}" style="z-index: 9;" v-show="turtle >= 6">
            <img src="@/assets/game-img/turtle/turtle.png" style="width:200px;" />
          </div>
          <div :class="{'turtle': true, 'new3':turtle==4}" style="z-index: 8;" v-show="turtle >= 4">
            <img src="@/assets/game-img/turtle/turtle.png" style="width:200px;" />
          </div>
          <div :class="{'turtle': true, 'new2':turtle==2}" style="z-index: 7;" v-show="turtle >= 2">
            <img src="@/assets/game-img/turtle/turtle.png" style="width:200px;" />
          </div>
          <div :class="{'turtle': true, 'new1':turtle==0}" style="z-index: 6;" v-show="turtle >= 0">
            <img src="@/assets/game-img/turtle/turtle.png" style="width:200px;" />
          </div>
          <div class="turtle basic" style="z-index: 5;">
            <img src="@/assets/game-img/turtle/turtle.png" style="width:200px;" />
          </div>
        </div>
      </div>
      <div class="game-btn-circle start" @click="start">
        开 始
      </div>
    </div>
  </div>
</template>

<script>
import { ref, onMounted, onUnmounted } from 'vue';

export default {
  name: "Turtle",
  setup() {
    const turtle = ref(-1)
    const falling = ref(false)

    function start() {
      console.log(turtle.value)
      if(!falling.value){
        if(turtle.value >= 9){
          turtle.value = -1
        }else if(turtle.value == -1){
          turtle.value = 0
        }else{
          turtle.value++
          falling.value = true
          setTimeout(function () {
            if(true){
              turtle.value++
              falling.value = false
            }else{
              console.log("game over!")
              turtle.value = -1
            }
          },1200)
          
        }
      }
    }

    return {
      turtle,
      start
    }
  }
}
</script>

<style scoped>
  .container {
    margin: 20px 30px;
    border: var(--box-border);
    border-radius:12px;
    display: flex;
    flex-direction: column;
    text-align: center;
    align-items: center;
    background-color: var(--box-bgc);
  }

  .game {
    background-color: #fff;
    width: 350px;
    height: 500px;
  }

  .turtles{
    height: 420px;
  }

  .turtle-game{
    display: flex;
    flex-direction: column;
    justify-content: end;
/*    background-color: #bbb;*/
    height: 100%;
  }

  .turtle-list{
    position: absolute;
    display: flex;
    flex-direction: column;
  }

  .turtle-item{
    width: 15px;
    height: 15px;
    border-radius: 50%;
    border: 1px solid #363636;
    margin-bottom: 2px;
  }

  .turtle {
/*    margin-bottom: -5px;*/
/*    transform: translateY(-100%);*/
/*    background-image: url("../assets/game-img/turtle/turtle.png");*/
/*    background-size:100% 100%;*/
    margin-bottom: -40px;
    margin-left: auto;
    margin-right: auto;
    width: 200px;
    background: none;
/*    height: 100px;*/
/*    border-radius: 50%;*/
/*    border:1px solid #363636;*/
    transition: margin-bottom 1s ease-in;
    animation-name: scaleAnimate; 
    animation-duration: 2s; 
    animation-iteration-count: infinite; 
    animation-timing-function: linear;
    animation-play-state: paused;

    position: relative;
  }

  .new1{
    margin-bottom: calc(100% -  100px);
    animation-play-state: running;
  }
  .new2{
    margin-bottom: calc(100% - 120px);
    animation-play-state: running;
  }
  .new3{
    margin-bottom: calc(100% - 150px);
    animation-play-state: running;
  }
  .new4{
    margin-bottom: calc(100% - 170px);
    animation-play-state: running;
  }
  .new5{
    margin-bottom: calc(100% - 190px);
    animation-play-state: running;
  }

  @keyframes scaleAnimate{
    0% {transform:scale(1.0);}
    25% {transform:scale(1.5);}
    50% {transform:scale(1.0);}
    75% {transform:scale(0.5);}
    100% {transform:scale(1.0);}
  }


  .basic{
/*    transform: translateY(0);*/
    margin-bottom: -5px;
    transform:scale(1.0);
  }

  
</style>

